Drupal.behaviors.accordion={attach(o){o.querySelectorAll(".accordion")&&o.querySelectorAll(".accordion__header").forEach(r=>{r.addEventListener("click",n=>{this.toggleAccordion(n)})})},toggleAccordion(o){const c=o.currentTarget,e=c.parentNode.classList.contains("accordion--open");this.closeAccordions(),e||this.openAccordion(c)},closeAccordions(){document.querySelectorAll(".accordion").forEach(c=>{c.classList.remove("accordion--open"),c.firstElementChild.setAttribute("aria-expanded","false")})},openAccordion(o){o.parentNode.classList.add("accordion--open"),o.setAttribute("aria-expanded","true")}};
